#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

typedef struct Edge {int to; long long w; struct Edge *next;} Edge;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        Edge **adj = (Edge**)calloc(N+1, sizeof(Edge*));
        for (int i=0;i<M;i++){
            int u,v; long long w; scanf("%d %d %lld", &u, &v, &w);
            Edge *e1 = (Edge*)malloc(sizeof(Edge)); e1->to=v; e1->w=w; e1->next=adj[u]; adj[u]=e1;
            Edge *e2 = (Edge*)malloc(sizeof(Edge)); e2->to=u; e2->w=w; e2->next=adj[v]; adj[v]=e2;
        }
        const long long INF = 9e18;
        long long *dist = (long long*)malloc((N+1)*sizeof(long long));
        for (int i=1;i<=N;i++) dist[i]=INF;
        dist[1]=0;
        // binary heap (min‑heap) implementation
        int heapSize = 0;
        int cap = N*2+5;
        int *heapV = (int*)malloc(cap*sizeof(int));
        long long *heapD = (long long*)malloc(cap*sizeof(long long));
        // push function
        #define PUSH(d,v) do{ heapSize++; int i=heapSize; while(i>1 && heapD[i/2]>d){ heapD[i]=heapD[i/2]; heapV[i]=heapV[i/2]; i/=2; } heapD[i]=d; heapV[i]=v; }while(0)
        #define POP(d,v) do{ d=heapD[1]; v=heapV[1]; heapD[1]=heapD[heapSize]; heapV[1]=heapV[heapSize]; heapSize--; int i=1; while(1){ int l=i*2, r=l+1, smallest=i; if(l<=heapSize && heapD[l]<heapD[smallest]) smallest=l; if(r<=heapSize && heapD[r]<heapD[smallest]) smallest=r; if(smallest==i) break; heapD[i]=heapD[smallest]; heapV[i]=heapV[smallest]; i=smallest; } }while(0)
        PUSH(0,1);
        while (heapSize) {
            long long d; int v; POP(d,v);
            if (d!=dist[v]) continue;
            for (Edge *e=adj[v]; e; e=e->next) {
                if (dist[e->to] > d + e->w) {
                    dist[e->to] = d + e->w;
                    PUSH(dist[e->to], e->to);
                }
            }
        }
        for (int i=1;i<=N;i++) {
            if (dist[i]==INF) printf("-1"); else printf("%lld", dist[i]);
            if (i<N) printf(" ");
        }
        printf("\n");
        // free memory
        for (int i=1;i<=N;i++) {
            Edge *e=adj[i]; while(e){ Edge *tmp=e; e=e->next; free(tmp);} }
        free(adj); free(dist); free(heapV); free(heapD);
    }
    return 0;
}

