            int u,v; ll w; cin>>u>>v>>w;
            adj[u].push_back({v,w});
            adj[v].push_back({u,w});
        }
        vector<ll> dist(N+1, INF);
        dist[1]=0;
        priority_queue<pair<ll,int>, vector<pair<ll,int>>, greater<pair<ll,int>>> pq;
        pq.push({0,1});
        while(!pq.empty()){
            auto [d,u]=pq.top(); pq.pop();
            if(d!=dist[u]) continue;
            for(auto [v,w]:adj[u]){
                if(dist[v]>d+w){
                    dist[v]=d+w;
                    pq.push({dist[v],v});
                }
            }
        }
        for(int i=1;i<=N;i++){
            if(dist[i]==INF) cout<<-1;
            else cout<<dist[i];
            if(i<N) cout<<' ';
        }
        cout<<'\n';
