const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (input.length===0) process.exit(0);
const T = input[idx++];
let outputs = [];
const INF = 9n ** 18n; // large enough
for (let tc = 0; tc < T; tc++) {
  const N = input[idx++];
  const M = input[idx++];
  const adj = Array.from({length: N+1}, () => []);
  for (let i = 0; i < M; i++) {
    const u = input[idx++];
    const v = input[idx++];
    const w = BigInt(input[idx++]);
    adj[u].push([v, w]);
    adj[v].push([u, w]);
  }
  const dist = Array(N+1).fill(INF);
  dist[1] = 0n;
  // binary heap (min‑heap) using array
  const heap = [];
  const push = (d, v) => {
    heap.push([d, v]);
    let i = heap.length - 1;
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (heap[p][0] <= heap[i][0]) break;
      [heap[p], heap[i]] = [heap[i], heap[p]];
      i = p;
    }
  };
  const pop = () => {
    const top = heap[0];
    const last = heap.pop();
    if (heap.length) {
      heap[0] = last;
      let i = 0;
      while (true) {
        let l = i * 2 + 1, r = l + 1, smallest = i;
        if (l < heap.length && heap[l][0] < heap[smallest][0]) smallest = l;
        if (r < heap.length && heap[r][0] < heap[smallest][0]) smallest = r;
        if (smallest === i) break;
        [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
        i = smallest;
      }
    }
    return top;
  };
  push(0n, 1);
  while (heap.length) {
    const [d, u] = pop();
    if (d !== dist[u]) continue;
    for (const [v, w] of adj[u]) {
      const nd = d + w;
      if (nd < dist[v]) {
        dist[v] = nd;
        push(nd, v);
      }
    }
  }
  const line = [];
  for (let i = 1; i <= N; i++) {
    line.push(dist[i] === INF ? '-1' : dist[i].toString());
  }
  outputs.push(line.join(' '));
}
